#!/usr/bin/env bash
# design-sprint-5.sh — Design Sprint（5 天冲刺） SOP walkthrough for 产品设计 / UX 设计.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="产品设计 / UX 设计"
WORKFLOW="Design Sprint（5 天冲刺）"

usage() {
  cat <<EOF
design-sprint-5.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./design-sprint-5.sh             # interactive
  ./design-sprint-5.sh --dry-run
  ./design-sprint-5.sh --json
  ./design-sprint-5.sh --explain
  ./design-sprint-5.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Design Sprint（5 天冲刺）" 工作流。

一句话: 从「有个高风险大赌注，不确定值不值得建」到「5 天内得到真人测过的高保真原型 + go/no-go 决策」，跳过数月辩论。

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 行为 > 自陈（You are not the user）: 设计决策必须基于**观察到的真实行为**，而非设计师/利益相关者的意见、也不是用户口头说的偏好——"你不是用户"，"opinions are not data"。 (figures: Krug / H
  • 认知负荷最小化（Don't Make Me Think）: 好设计让"正确操作显而易见"，把思考成本从用户身上移走——识别（recognition）优于回忆（recall），扫读优于阅读，满意即止（satisficing）。 (figures: Krug / 

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**周一 Map（理解+定目标）**: 画长期目标、流程地图、采访专家、选一个 sprint 靶点。跳过→后面四天没有共同焦点，原型散乱。 (evidence: [T03-S008])"
  "**周二 Sketch（构思）**: 找灵感（lightning demos）+ 每人独立画方案（crazy 8s / solution sketch）。跳过→只剩 HiPPO 的点子，丧失方案多样性。 (evidence: [T03-S008])"
  "**周三 Decide（决策）**: 投票（dot voting）+ Decider 拍板 + 画 storyboard。跳过→无收敛，周四不知道原型造什么。 (evidence: [T03-S008])"
  "**周四 Prototype（造原型）**: 用 Figma 等做「门面（facade）」级高保真假象，只做被测路径。跳过→周五没东西可测。 (evidence: [T03-S008])"
  "**周五 Test（测试）**: 1:1 访谈式测 5 个目标用户，团队观看，归纳模式得结论。跳过→等于又做了一个没验证的方案。 (evidence: [T03-S008, T03-S005])"
)
declare -a FAILURE_MODES=(
  "对低风险问题用 sprint: 杀鸡用牛刀，浪费全团队一周。先问「这值得 5 个人停一周吗」。 (evidence: [T03-S009])"
  "原型做太真: 想做完整产品级原型，周四做不完。只做被测路径的「门面」，其余假装。 (evidence: [T03-S008])"
  "跳过周五测试: 时间紧就砍测试 — 那 sprint 就退化成普通 workshop，验证为 0。测试是不可跳的核心。 (evidence: [T03-S008])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "design-sprint-5-walkthrough"
fi
